var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"크흑……!!","JPN":"くっ……！！","ENG":"Ghk...!!","TWN":"咳……！！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"보이지 않는 참격이라, 상상 이상으로 성가신 능력이로군…….","JPN":"目に見えない斬撃か。想像以上に厄介な能力だ……","ENG":"Invisible slashes. Far more troublesome than I imagined...","TWN":"看不見的斬擊，真是比想像中還棘手的能力……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"하지만……!","JPN":"だが……！","ENG":"But...!","TWN":"不過……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"아직도 저항할 셈인가?","JPN":"まだ抵抗する気か？","ENG":"Do you still intend to resist?","TWN":"你還打算抵抗嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"큭, 팔을……!!","JPN":"くっ、腕を……！！","ENG":"Ghk, my arm...!!","TWN":"呃，我的手臂……！！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"방금, 네 오른팔의 힘줄을 끊었다.","JPN":"今、右腕の腱を斬った。","ENG":"Just now, I severed the tendons in your right arm.","TWN":"剛才我切斷了你右臂的肌腱。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"아무리 금서로 고통을 억누르고, 운동 신경을 채찍질해 봤자 한계겠지.","JPN":"禁書の力で苦痛を抑え、運動神経を向上させたところで、限界はある。","ENG":"No matter how much you dull the pain with the forbidden book and whip your motor nerves into motion, there are limits.","TWN":"就算用禁書壓制痛苦、強行驅使神經也有極限。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"카운터라고 해도, CRF 간섭에 의한 심각한 부상은 틀림없이 후유증이 남게 되어있어.","JPN":"そして、いくらカウンターであろうと、CRFの干渉による深刻な負傷には必ず後遺症が残る。","ENG":"Even for a Counter, severe injuries caused by CRF interference are guaranteed to leave lasting aftereffects.","TWN":"就算是制裁者，受到CRF干涉造成的重傷，也必定會留下後遺症。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"더는 저항하지 않는 편이 네 신상에 좋을 거다. 콘스탄틴.","JPN":"これ以上の抵抗はやめたほうが身のためだ、コンスタンティン。","ENG":"It would be in your best interest to resist no further, Constantine.","TWN":"別再反抗對你比較好，康斯坦丁。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"법학부장님, 대균열로 접근하려던 사교도들을 전원 제압했습니다.","JPN":"法学部長、大亀裂に接近しようとしていた邪教徒をすべて制圧しました。","ENG":"Ma'am, we have subdued all cultists who were attempting to approach the Grand Dimension Crevice.","TWN":"法學院院長，已全數制伏試圖接近大峽谷的邪教徒。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"전원 처형하고, 모든 증거를 말소하도록.","JPN":"全員処刑し、関連する証拠を残らず抹消するように。","ENG":"Execute them all, and erase every trace.","TWN":"全部處刑，並抹滅所有證據。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"우리는 이 세계의 그림자다. 누구도 이런 해프닝이 발생했다는 걸 알아서는 안 돼.","JPN":"私たちはこの世界の影。こんなハプニングが起きたことを誰にも知られてはいけない。","ENG":"We are the shadows of this world. No one must ever learn that such an incident occurred.","TWN":"我們是這個世界的影子，不能讓任何人知道曾經發生這場騷動。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"사건의 배후에 무엇이 있는지는, 내가 직접 이 자를 심문하여 밝히겠다.","JPN":"事件の裏に何があるかは、私が直接この者を審問して解き明かす。","ENG":"As for what lies behind this affair, I will interrogate this one personally and uncover the truth.","TWN":"我會親自審問這傢伙，釐清事件背後的真相。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"크으, 커헉……!","JPN":"くうっ、かはっ……！","ENG":"Gkh... Kuh...!","TWN":"咳、咳……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"자, 구두 변론 기회를 주지.","JPN":"さて、口頭弁論の機会を与えよう。","ENG":"Now then, I will grant you an opportunity for oral argument.","TWN":"來吧，我給你辯解的機會。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"경우에 따라서는, 최후 진술이 될 수도 있으니 신중히 발언하도록.","JPN":"返答次第では最後の陳述となる可能性もある。慎重に発言したほうがいい。","ENG":"Depending on how this goes, it may be your final statement, so choose your words carefully.","TWN":"根據情況，這很有可能是你最後的陳述，希望你謹慎發言。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"네놈에게 묻고 싶은 건 한 가지뿐이다.","JPN":"貴様に聞きたいことは1つだけだ。","ENG":"There is only one thing I wish to ask you.","TWN":"我只問你一件事。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"네놈이 학회 반역자들과 내통하고 있다는 건, 알고 있다.","JPN":"貴様が学会の反逆者どもと内通していることは知っている。","ENG":"I am aware that you are colluding with the Society's traitors.","TWN":"我已經知道你與學會叛徒們私通一事了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"하지만 네놈이 납치를 시도한 그 여자 아이…….","JPN":"しかし貴様が誘拐しようとしたその女の子……","ENG":"However, the girl you attempted to abduct...","TWN":"但你試圖綁架的那個少女……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"리오나 하트가 그릇의 소질이 있다는 것은 학회 내에서도 일부만 알고 있는 정보야.","JPN":"リオナ・ハートが器の素質を持っていることは、学会でもごく一部の者しか知らない情報だ。","ENG":"That Liona Hartt has the potential to become a vessel is information known only to a select few within the Society.","TWN":"萊歐娜．哈特具備成為器皿的資質，在學會內部也只有少數人知情。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"애초에 신을 담는 그릇이라는 건, 카운터 중에서도 무척 희귀한 케이스…….","JPN":"そもそも神を宿す器はカウンターの中でも非常に稀なケース……","ENG":"To begin with, those capable of becoming vessels to contain a god are exceedingly rare, even among Counters.","TWN":"神之器皿本就是制裁者之中極為罕見的案例……"},"stage":{"bg":"MYEONGDONG_DARK","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"사고 이후, 잠적해 버린 리오나의 신상이 표면에 드러난 것도 비교적 최근 일이지.","JPN":"事故の後に姿を消していたリオナが表に姿を現したのも、比較的最近のこと。","ENG":"After the incident, Liona vanished, and her identity resurfacing is a relatively recent development.","TWN":"事發後銷聲匿跡的萊歐娜，身分再次浮上檯面也只是最近的事。"},"stage":{"bg":"MYEONGDONG_DARK","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그렇다면, 네놈에게 리오나 하트에 관한 정보를 누설한 자가 있을 거다.","JPN":"だとしたら、貴様にリオナ・ハートの情報を漏洩した誰かがきっといたはず。","ENG":"That means someone leaked information about Liona Hartt to you.","TWN":"也就是說，有人將萊歐娜．哈特的情報洩漏給你。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그자의 이름을 말해라. 말한다면, 목숨만은 살려주지.","JPN":"その者の名前を言え。言えば命だけは助けてやる。","ENG":"Speak their name. Do that, and I will spare your life.","TWN":"說出那個人的名字，我可以饒你一命。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"큭큭, 제법 훌륭한 변호사군.","JPN":"くくっ、なかなか優秀な弁護士だ。","ENG":"Haha, a rather competent lawyer you are.","TWN":"呵呵，真是位優秀的律師。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"단편적인 상황만으로 내통자의 존재를 암시하며, 협상을 시도하다니…….","JPN":"断片的な状況だけで内通者の存在を仄めかし、交渉を試みるとは……","ENG":"To imply the existence of an accomplice based on fragmentary circumstances, and then attempt a negotiation...","TWN":"僅憑片面的情況就暗示內賊的存在，試圖進行談判……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"묻고 싶은 건 한 가지뿐이라고 했을 텐데?","JPN":"聞かれたことだけに答えろ。","ENG":"I said there was only one thing I wished to ask.","TWN":"我不是說了，我只想問一件事嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그 입에서 나오는 다음 발언도 가치가 없다면, 정말로 목을 거두겠다.","JPN":"その口から出てくる次の発言も無価値なものなら、今度こそその首を切り落とす。","ENG":"If your next words hold no value either, I will take your head.","TWN":"如果你接下來的發言仍然毫無價值，我真的會要了你的命。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"과연, 그 여자의 말대로군.","JPN":"なるほど、あの女の言ったとおりか。","ENG":"So it seems. Just as that woman said.","TWN":"果然和那個女人說的一樣。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"실력은 제법 출중하지만, 아직 연륜이 부족해.","JPN":"実力はずば抜けているが、まだ経験が足りない。","ENG":"Your skills are respectable, but you still lack experience.","TWN":"實力不錯，但經驗還不夠。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"그 여자라고……?","JPN":"あの女……？","ENG":"Woman...?","TWN":"那個女人……？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};